package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.Map;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EmptyTripleSource;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.OptimizationTraceSink;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class JoinMemoDeterminismTest {

	@Test
	void subsetDpBreaksEqualScoresWithLowerRisk() {
		StatementPattern a = statement("a", "urn:pA");
		StatementPattern b = statement("b", "urn:pB");
		StatementPattern c = statement("c", "urn:pC");
		JoinRegion region = new JoinRegion(List.of(a, b, c), List.of(), Set.of(), null);
		JoinOptimizationContext context = context(0.0d, new LeftMostRiskEstimator());

		List<JoinOrderCandidate> candidates = new JoinMemo().expandSubsetDpCandidates(region, context, 1);

		assertThat(candidates).hasSize(1);
		assertThat(candidates.getFirst().getSignature())
				.as("Expected lower-risk order to win when scores tie")
				.startsWith("[2,");
	}

	private StatementPattern statement(String suffix, String predicateIri) {
		return new StatementPattern(
				new Var("s" + suffix),
				new Var("p" + suffix, SimpleValueFactory.getInstance().createIRI(predicateIri)),
				new Var("o" + suffix));
	}

	private JoinOptimizationContext context(double riskPenaltyWeight, UncertaintyAwareEstimator estimator) {
		JoinEngineConfig defaults = JoinEngineConfig.defaults();
		JoinEngineConfig config = new JoinEngineConfig(true, riskPenaltyWeight, defaults.getDpThreshold(),
				Math.max(3, defaults.getPortfolioSize()), true, defaults.isAdaptiveFallbackEnabled(),
				defaults.getAdaptiveFallbackRiskThreshold(), defaults.getAdaptiveFallbackMinGainRatio(),
				defaults.isRuntimeFeedbackEnabled());
		return new JoinOptimizationContext(new EvaluationStatistics(), new EmptyTripleSource(), null,
				EmptyBindingSet.getInstance(), Set.of(), config, OptimizationTraceSink.NOOP, BanditPolicy.noop(),
				estimator, new DefaultCostModel());
	}

	private static final class LeftMostRiskEstimator implements UncertaintyAwareEstimator {

		@Override
		public Estimate estimateRows(TupleExpr expr, JoinOptimizationContext ctx) {
			String leftMostPredicate = leftMostPredicate(expr);
			double risk = switch (leftMostPredicate) {
			case "urn:pA" -> 0.90d;
			case "urn:pB" -> 0.50d;
			case "urn:pC" -> 0.10d;
			default -> 0.50d;
			};
			return new Estimate(10.0d, risk, "TEST", Map.of("leftMostPredicate", leftMostPredicate));
		}

		private String leftMostPredicate(TupleExpr expr) {
			TupleExpr current = expr;
			while (current instanceof Join) {
				current = ((Join) current).getLeftArg();
			}
			if (current instanceof StatementPattern) {
				StatementPattern statementPattern = (StatementPattern) current;
				Var predicate = statementPattern.getPredicateVar();
				if (predicate != null && predicate.hasValue()) {
					return predicate.getValue().stringValue();
				}
			}
			return "unknown";
		}
	}
}
